import React from 'react'; 
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom'; 
import Home from './pages/Home/Home'; 
import Search from './pages/Search/Search'; 
 
function App() { 
  return ( 
    <Router> 
      <nav style={{ padding: '15px 40px', background: '#f8f9fa', display: 'flex', gap: '30px', boxShadow: '0 2px 5px rgba(0,0,0,0.1)', alignItems: 'center' }}> 
        <Link to="/" style={{fontWeight:'bold', textDecoration:'none', color:'#333'}}>TRANG CHỦ</Link> 
        <Link to="/search" style={{fontWeight:'bold', textDecoration:'none', color:'#28a745'}}>🔍 TÌM KIẾM</Link> 
      </nav> 
      <Routes> 
        <Route path="/" element={<Home />} /> 
        <Route path="/search" element={<Search />} /> 
      </Routes> 
    </Router> 
  ); 
} export default App;
